#include <iostream>
#include <vector>
using namespace std;

bool isPrime(int number)
{
    if (number < 2) return false;

    for (int i = 2; i * i <= number; i++)
    {
        if (number % i == 0) return false;
    }
    return true;
}

int main()
{
    cout << "1-50 arasindaki asal sayilar:" << endl;
    vector<int> primes;

    for (int i = 1; i <= 50; i++)
    {
        if (isPrime(i))
        {
            primes.push_back(i);
        }
    }

    for (int p : primes) cout << p << " ";
    cout << endl;

    cout << "\nToplam asal sayi adedi: " << primes.size() << endl;

    // Tekil kontrol
    int testNumber = 97;
    cout << "\n" << testNumber << " asal mi: " << isPrime(testNumber) << endl;

    testNumber = 100;
    cout << testNumber << " asal mi: " << isPrime(testNumber) << endl;

    return 0;
}
